const contentResponse = $input.first().json;
const webhookData = $('Webhook').first().json.body;

let title = webhookData.productName || 'Amigurumi';
let description = '';
let tags = [];

try {
  const txt = contentResponse.candidates?.[0]?.content?.parts?.[0]?.text;
  if (txt) {
    const parsed = JSON.parse(txt);
    title = parsed.title || title;
    description = parsed.description || '';
    tags = parsed.tags || [];
  }
} catch(e) {}

const PRESETS = {
  'simple-table': { label: 'Sade Ev - Masa Ustu', prompt: 'Place the amigurumi toy on a clean wooden dining table in a simple bright minimalist home. Soft natural window light, clean white walls.' },
  'kids-room-carpet': { label: 'Cocuk Odasi - Hali Ustu', prompt: 'Place the amigurumi toy on a soft colorful carpet in a bright childrens room. Pastel walls, toys in soft bokeh background.' },
  'living-room-sofa': { label: 'Oturma Odasi - Kanepe', prompt: 'Place the amigurumi toy on a cozy beige sofa in a modern living room. Soft cushions, warm ambient lighting.' },
  'bedroom-bed': { label: 'Yatak Odasi - Yatak Ustu', prompt: 'Place the amigurumi toy on a neatly made bed with white soft bedding. Cozy bedroom, soft morning light.' },
  'window-sill': { label: 'Pencere Kenari', prompt: 'Place the amigurumi toy on a bright window sill with natural daylight. Soft blurred outdoor greenery visible.' },
  'bookshelf': { label: 'Kitaplik Onu', prompt: 'Place the amigurumi toy in front of a cozy bookshelf with colorful books. Warm lighting, hygge atmosphere.' },
  'kitchen-counter': { label: 'Mutfak Tezgahi', prompt: 'Place the amigurumi toy on a clean white marble kitchen counter. Bright modern kitchen, warm natural light.' },
  'baby-room-crib': { label: 'Bebek Odasi', prompt: 'Place the amigurumi toy next to a white baby crib in a pastel nursery room. Gentle lighting, dreamy atmosphere.' },
  'fireplace': { label: 'Somine Onu', prompt: 'Place the amigurumi toy on a cozy rug in front of a warm fireplace. Golden glow, knit blanket nearby.' },
  'balcony-table': { label: 'Balkon - Sehpa', prompt: 'Place the amigurumi toy on a small coffee table on a cozy balcony. Green plants, soft outdoor light.' }
};

const items = [];
for (const bgId of (webhookData.backgroundIds || [])) {
  const preset = PRESETS[bgId];
  if (!preset) continue;
  items.push({
    json: {
      geminiPrompt: 'Edit this image: Remove the current background completely and replace it with: ' + preset.prompt + ' Keep the amigurumi toy EXACTLY as it is. Professional product photography.',
      backgroundId: bgId,
      backgroundLabel: preset.label,
      title, description, tags,
      productId: webhookData.productId,
      callbackUrl: webhookData.callbackUrl,
      secret: webhookData.secret
    }
  });
}

if (items.length === 0) throw new Error('No valid backgrounds');
return items;

const crypto = require('crypto');
const CLOUD_SECRET = '9XsIgOi01RoxfE3PnRi0zWuZkEM';

const allResponses = $input.all();
const fanOutItems = $('Fan Out').all();
const results = [];

for (let i = 0; i < allResponses.length; i++) {
  const response = allResponses[i].json;
  const bgInfo = fanOutItems[i]?.json;
  if (!bgInfo) continue;

  let imageBase64 = null;
  const parts = response.candidates?.[0]?.content?.parts || [];
  for (const part of parts) {
    if (part.inlineData?.data) { imageBase64 = part.inlineData.data; break; }
  }
  if (!imageBase64) continue;

  const ts = Math.floor(Date.now() / 1000).toString();
  const folder = 'amigurumi/gemini';
  const sig = crypto.createHash('sha1').update('folder=' + folder + '&timestamp=' + ts + CLOUD_SECRET).digest('hex');

  results.push({
    json: {
      imageBase64,
      cloudTs: ts,
      cloudSig: sig,
      backgroundId: bgInfo.backgroundId,
      backgroundLabel: bgInfo.backgroundLabel,
      title: bgInfo.title,
      description: bgInfo.description,
      tags: bgInfo.tags,
      productId: bgInfo.productId,
      callbackUrl: bgInfo.callbackUrl,
      secret: bgInfo.secret
    }
  });
}

if (results.length === 0) {
  const bg = fanOutItems[0]?.json || {};
  return [{ json: { noImages: true, productId: bg.productId, callbackUrl: bg.callbackUrl, secret: bg.secret, title: bg.title || '', description: bg.description || '', tags: bg.tags || [] } }];
}
return results;

const uploadResults = $input.all();
const prepItems = $('Prep Upload').all();

const images = [];
let title = '', description = '', tags = [], productId = '', callbackUrl = '', secret = '';

for (let i = 0; i < prepItems.length; i++) {
  const prep = prepItems[i].json;
  const upload = uploadResults[i]?.json;

  if (!productId) {
    title = prep.title || '';
    description = prep.description || '';
    tags = prep.tags || [];
    productId = prep.productId;
    callbackUrl = prep.callbackUrl;
    secret = prep.secret;
  }

  if (upload?.secure_url) {
    images.push({ url: upload.secure_url, backgroundId: prep.backgroundId, backgroundLabel: prep.backgroundLabel });
  }
}

if (!callbackUrl) {
  const first = prepItems[0]?.json || {};
  callbackUrl = first.callbackUrl;
  secret = first.secret;
  productId = first.productId;
}

return [{
  json: {
    callbackUrl: callbackUrl,
    callbackBody: { secret, type: 'generate-result', productId, images, title, description, tags }
  }
}];
